import{ResolverFactory}from"oxc-resolver";import{DEFAULT_EXTENSIONS}from"../constants.js";import{timerify}from"./Performance.js";import{toPosix}from"./path.js";const createSyncModuleResolver=e=>{const o=new ResolverFactory({tsconfig:"auto",extensions:e,extensionAlias:{".js":[".js",".ts"],".jsx":[".jsx",".tsx"],".mjs":[".mjs",".mts"],".cjs":[".cjs",".cts"]},conditionNames:["require","import","node","default"],nodePath:!1});return function(e,t){try{const s=o.resolveFileSync(t,e);if(s?.path)return toPosix(s.path)}catch(e){}}};export const resolveModuleSync=createSyncModuleResolver([...DEFAULT_EXTENSIONS,".json",".jsonc"]);export{createSyncModuleResolver};const createSyncResolver=e=>{const o=new ResolverFactory({extensions:e,conditionNames:["require","import","node","default"],nodePath:!1});return function(e,t){try{const s=o.sync(t,e);if(s?.path)return toPosix(s.path)}catch(e){}}},resolveSync=createSyncResolver([...DEFAULT_EXTENSIONS,".d.ts",".d.mts",".d.cts",".json",".jsonc"]);export const _resolveSync=timerify(resolveSync);